using System; using UnityEngine; using UnityEngine.UI; namespace DungeonSlash { public sealed class ShopItemView : MonoBehaviour { [SerializeField] private Button button; [SerializeField] private Text label; public void Configure(Button newButton, Text newLabel) { button = newButton; label = newLabel; } public void Bind(EquipmentData item, bool affordable, Action<EquipmentData> buy) { label.text = $"{item.displayName}  {item.price}G\n<size=13>{item.description}</size>"; button.interactable = affordable; button.onClick.RemoveAllListeners(); button.onClick.AddListener(() => buy(item)); } } }
